// src/context/AppContext.js
import React, { createContext, useContext, useReducer, useEffect, useMemo } from 'react';
import { RECIPES, DAYS, MEAL_TYPES, DAILY_GOALS } from '../data/recipes';

const AppContext = createContext(null);

const initialPlanner = DAYS.reduce((acc, day) => {
  acc[day] = MEAL_TYPES.reduce((m, mt) => { m[mt] = []; return m; }, {});
  return acc;
}, {});

const loadFromStorage = () => {
  try {
    const saved = localStorage.getItem('smartRecipePlanner');
    if (saved) return JSON.parse(saved);
  } catch (e) {}
  return null;
};

const initialState = {
  ingredients: [],
  recipes: RECIPES,
  planner: loadFromStorage()?.planner || initialPlanner,
  darkMode: loadFromStorage()?.darkMode || false,
  activeNav: 'Dashboard',
  filters: { type: 'all', maxCalories: 1000, maxTime: 120 },
  shoppingChecked: {},
};

function reducer(state, action) {
  switch (action.type) {
    case 'ADD_INGREDIENT':
      if (state.ingredients.includes(action.payload)) return state;
      return { ...state, ingredients: [...state.ingredients, action.payload] };
    case 'REMOVE_INGREDIENT':
      return { ...state, ingredients: state.ingredients.filter((_, i) => i !== action.index) };
    case 'CLEAR_INGREDIENTS':
      return { ...state, ingredients: [] };
    case 'ADD_TO_PLANNER': {
      const { day, mealType, recipe } = action.payload;
      const existing = state.planner[day][mealType];
      if (existing.find(r => r.id === recipe.id)) return state;
      return {
        ...state,
        planner: {
          ...state.planner,
          [day]: {
            ...state.planner[day],
            [mealType]: [...existing, recipe],
          },
        },
      };
    }
    case 'REMOVE_FROM_PLANNER': {
      const { day, mealType, recipeId } = action.payload;
      return {
        ...state,
        planner: {
          ...state.planner,
          [day]: {
            ...state.planner[day],
            [mealType]: state.planner[day][mealType].filter(r => r.id !== recipeId),
          },
        },
      };
    }
    case 'MOVE_MEAL': {
      const { fromDay, fromMealType, toDay, toMealType, recipe } = action.payload;
      const fromList = state.planner[fromDay][fromMealType].filter(r => r.id !== recipe.id);
      const toList = state.planner[toDay][toMealType];
      if (toList.find(r => r.id === recipe.id)) return state;
      return {
        ...state,
        planner: {
          ...state.planner,
          [fromDay]: { ...state.planner[fromDay], [fromMealType]: fromList },
          [toDay]: { ...state.planner[toDay], [toMealType]: [...toList, recipe] },
        },
      };
    }
    case 'SET_FILTER':
      return { ...state, filters: { ...state.filters, ...action.payload } };
    case 'TOGGLE_DARK_MODE':
      return { ...state, darkMode: !state.darkMode };
    case 'SET_ACTIVE_NAV':
      return { ...state, activeNav: action.payload };
    case 'TOGGLE_SHOPPING_ITEM':
      return {
        ...state,
        shoppingChecked: {
          ...state.shoppingChecked,
          [action.payload]: !state.shoppingChecked[action.payload],
        },
      };
    case 'CLEAR_SHOPPING_CHECKED':
      return { ...state, shoppingChecked: {} };
    default:
      return state;
  }
}

export function AppProvider({ children }) {
  const [state, dispatch] = useReducer(reducer, initialState);

  useEffect(() => {
    localStorage.setItem('smartRecipePlanner', JSON.stringify({
      planner: state.planner,
      darkMode: state.darkMode,
    }));
  }, [state.planner, state.darkMode]);

  useEffect(() => {
    if (state.darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state.darkMode]);

  const filteredRecipes = useMemo(() => {
    const ing = state.ingredients.map(i => i.toLowerCase());
    return state.recipes
      .map(recipe => {
        const matched = ing.length
          ? recipe.ingredients.filter(i => ing.includes(i.toLowerCase())).length
          : recipe.ingredients.length;
        const pct = ing.length
          ? Math.round((matched / recipe.ingredients.length) * 100)
          : 100;
        return { ...recipe, matchPct: pct, matchedCount: matched };
      })
      .filter(r => {
        if (state.filters.type !== 'all' && r.type !== state.filters.type) return false;
        if (r.calories > state.filters.maxCalories) return false;
        if (r.time > state.filters.maxTime) return false;
        if (ing.length > 0 && r.matchPct === 0) return false;
        return true;
      })
      .sort((a, b) => b.matchPct - a.matchPct);
  }, [state.ingredients, state.recipes, state.filters]);

  const weeklyNutrition = useMemo(() => {
    const totals = { calories: 0, protein: 0, carbs: 0, fat: 0 };
    Object.values(state.planner).forEach(day => {
      Object.values(day).forEach(meals => {
        meals.forEach(meal => {
          totals.calories += meal.calories;
          totals.protein += meal.protein;
          totals.carbs += meal.carbs;
          totals.fat += meal.fat;
        });
      });
    });
    return totals;
  }, [state.planner]);

  const todayNutrition = useMemo(() => {
    const today = DAYS[new Date().getDay() === 0 ? 6 : new Date().getDay() - 1];
    const totals = { calories: 0, protein: 0, carbs: 0, fat: 0 };
    if (state.planner[today]) {
      Object.values(state.planner[today]).forEach(meals => {
        meals.forEach(meal => {
          totals.calories += meal.calories;
          totals.protein += meal.protein;
          totals.carbs += meal.carbs;
          totals.fat += meal.fat;
        });
      });
    }
    return totals;
  }, [state.planner]);

  const shoppingList = useMemo(() => {
    const allIngredients = {};
    Object.values(state.planner).forEach(day => {
      Object.values(day).forEach(meals => {
        meals.forEach(meal => {
          meal.ingredients.forEach(ing => {
            allIngredients[ing] = (allIngredients[ing] || 0) + 1;
          });
        });
      });
    });
    return allIngredients;
  }, [state.planner]);

  const totalPlannedMeals = useMemo(() => {
    let count = 0;
    Object.values(state.planner).forEach(day =>
      Object.values(day).forEach(meals => { count += meals.length; })
    );
    return count;
  }, [state.planner]);

  const smartSuggestions = useMemo(() => {
    const suggestions = [];
    const goals = DAILY_GOALS;
    const ratio = todayNutrition.calories / goals.calories;
    if (ratio < 0.5 && totalPlannedMeals > 0) suggestions.push({ type: 'warning', msg: "You're under your calorie goal today." });
    if (ratio > 1.1) suggestions.push({ type: 'danger', msg: "You've exceeded your daily calorie goal!" });
    if (todayNutrition.protein < goals.protein * 0.5 && totalPlannedMeals > 0) suggestions.push({ type: 'info', msg: "You're low on protein — add a protein-rich meal." });
    if (todayNutrition.carbs > goals.carbs * 1.1) suggestions.push({ type: 'warning', msg: "Your carb intake is above target." });
    return suggestions;
  }, [todayNutrition, totalPlannedMeals]);

  return (
    <AppContext.Provider value={{
      state, dispatch,
      filteredRecipes, weeklyNutrition, todayNutrition,
      shoppingList, totalPlannedMeals, smartSuggestions,
      dailyGoals: DAILY_GOALS,
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error('useApp must be used within AppProvider');
  return ctx;
}
